const fmt = (n) =>
  typeof n === 'number'
    ? '$' + n.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })
    : '—';

const fmtDate = (d) =>
  d ? new Date(d).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) : '';

function Frac({ n, d, sz = 13 }) {
  return (
    <span style={{ display: 'inline-flex', flexDirection: 'column', alignItems: 'center', verticalAlign: 'middle', lineHeight: 1, margin: '0 2px' }}>
      <span style={{ fontSize: sz, borderBottom: '1px solid currentColor', paddingBottom: 2, lineHeight: 1.4, whiteSpace: 'nowrap' }}>{n}</span>
      <span style={{ fontSize: sz, paddingTop: 2, lineHeight: 1.4, whiteSpace: 'nowrap' }}>{d}</span>
    </span>
  );
}

function EduEnrollCard({ user, onEnrolled }) {
  const [code, setCode] = useState('');
  const [status, setStatus] = useState(null); // null | {validating} | {course} | {error} | {enrolled}
  const timer = useRef(null);
  const { login } = useAuth();

  useEffect(() => {
    const raw = code.trim().toUpperCase();
    if (!raw) { setStatus(null); return; }
    setStatus({ validating: true });
    clearTimeout(timer.current);
    timer.current = setTimeout(async () => {
      try {
        const { data } = await api.post('/auth/validate-code', { code: raw });
        setStatus({ course: data.course });
      } catch {
        setStatus({ error: 'Code not found' });
      }
    }, 500);
    return () => clearTimeout(timer.current);
  }, [code]);

  const enroll = async () => {
    try {
      const { data } = await api.post('/auth/enroll', { code: code.trim().toUpperCase() });
      if (data.token && data.user) login(data.token, data.user);
      setStatus({ enrolled: true });
      setCode('');
      if (onEnrolled) onEnrolled();
    } catch (err) {
      setStatus({ error: err.response?.data?.error || 'Enrollment failed' });
    }
  };

  const enrollments = user?.enrollments || [];

  return (
    <div style={{ ...CARD, marginBottom: 16 }}>
      <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 4 }}>Courses</div>
      <div style={{ fontSize: 13, color: TEXT2, marginBottom: 16 }}>Your enrolled courses and Education Mode access.</div>

      {enrollments.length > 0 ? (
        <div style={{ marginBottom: 16 }}>
          {enrollments.map(e => (
            <div key={e.code} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '9px 0', borderBottom: `1px solid ${BORDER_C}` }}>
              <div>
                <div style={{ fontSize: 13, fontWeight: 600, color: TEXT }}>{e.course_name}</div>
                <div style={{ fontSize: 11, color: TEXT2 }}>{e.instructor_name} · {e.semester}</div>
              </div>
              <span style={{ fontSize: 10, fontWeight: 700, color: GREEN, background: 'rgba(74,222,128,0.1)', padding: '2px 8px', borderRadius: 4, letterSpacing: '0.5px', textTransform: 'uppercase' }}>{e.code}</span>
            </div>
          ))}
        </div>
      ) : (
        <div style={{ fontSize: 13, color: TEXT3, marginBottom: 16 }}>No courses enrolled yet.</div>
      )}

      <div style={{ fontSize: 10, color: TEXT3, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.8px', marginBottom: 8 }}>Add a Course</div>
      <div style={{ display: 'flex', gap: 8 }}>
        <input
          type="text" placeholder="Enter course code" value={code}
          onChange={e => setCode(e.target.value)}
          style={{ flex: 1, padding: '9px 12px', background: BG, border: status?.course ? '1px solid rgba(74,222,128,0.4)' : status?.error ? '1px solid rgba(248,113,113,0.35)' : BORDER, borderRadius: 8, color: TEXT, fontSize: 13, outline: 'none', textTransform: 'uppercase', letterSpacing: '1px' }}
        />
        <button onClick={enroll} disabled={!status?.course}
          style={{ padding: '9px 16px', background: status?.course ? 'rgba(74,222,128,0.1)' : MUTED, border: status?.course ? '1px solid rgba(74,222,128,0.3)' : BORDER, borderRadius: 8, color: status?.course ? GREEN : TEXT3, fontSize: 12, fontWeight: 700, cursor: status?.course ? 'pointer' : 'default', whiteSpace: 'nowrap' }}>
          Enroll
        </button>
      </div>
      {status?.validating && <div style={{ marginTop: 6, fontSize: 12, color: TEXT3 }}>Checking…</div>}
      {status?.course && <div style={{ marginTop: 6, fontSize: 12, color: GREEN }}>✓ {status.course.course_name} · {status.course.instructor_name}</div>}
      {status?.error && <div style={{ marginTop: 6, fontSize: 12, color: RED }}>{status.error}</div>}
      {status?.enrolled && <div style={{ marginTop: 6, fontSize: 12, color: GREEN }}>✓ Enrolled! Switching to Education Mode…</div>}
    </div>
  );
}

// Simple SVG line chart
function NetWorthChart({ snapshots }) {
  if (!snapshots || snapshots.length === 0) {
    return (
      <div style={{ height: 100, display: 'flex', alignItems: 'center', justifyContent: 'center', color: TEXT2, fontSize: 13 }}>
        No data yet. Loads on first use.
      </div>
    );
  }
  if (snapshots.length === 1) {
    return (
      <div style={{ padding: '16px 0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ color: TEXT2, fontSize: 13 }}>Started today. Chart builds up over time.</span>
        <span style={{ fontWeight: 700, fontSize: 18, fontFamily: 'monospace' }}>{fmt(snapshots[0].value)}</span>
      </div>
    );
  }

  const W = 600, H = 140, PAD = { top: 16, right: 16, bottom: 28, left: 64 };
  const innerW = W - PAD.left - PAD.right;
  const innerH = H - PAD.top - PAD.bottom;

  const values = snapshots.map(s => s.value);
  const minV = Math.min(...values);
  const maxV = Math.max(...values);
  const range = maxV - minV || 1;

  const toX = (i) => PAD.left + (i / (snapshots.length - 1)) * innerW;
  const toY = (v) => PAD.top + innerH - ((v - minV) / range) * innerH;

  const points = snapshots.map((s, i) => `${toX(i)},${toY(s.value)}`).join(' ');
  const areaPoints = `${PAD.left},${PAD.top + innerH} ${points} ${toX(snapshots.length - 1)},${PAD.top + innerH}`;

  // Pick a few evenly-spaced x-axis labels
  const labelCount = Math.min(snapshots.length, 6);
  const labelIdxs = Array.from({ length: labelCount }, (_, i) =>
    Math.round((i / (labelCount - 1)) * (snapshots.length - 1))
  );

  const latest = values[values.length - 1];
  const first  = values[0];
  const gain   = latest - first;
  const gainColor = gain >= 0 ? GREEN : RED;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: 12 }}>
        <span style={{ fontSize: 13, color: TEXT2 }}>Last {snapshots.length} day{snapshots.length !== 1 ? 's' : ''}</span>
        <span style={{ fontSize: 13, fontWeight: 600, color: gainColor, fontFamily: 'monospace' }}>
          {gain >= 0 ? '+' : ''}{fmt(gain)}
        </span>
      </div>
      <svg viewBox={`0 0 ${W} ${H}`} style={{ width: '100%', height: 'auto', display: 'block' }}>
        {/* Y-axis labels */}
        {[0, 0.5, 1].map(t => {
          const v = minV + t * range;
          const y = toY(v);
          return (
            <g key={t}>
              <line x1={PAD.left} x2={W - PAD.right} y1={y} y2={y} stroke={BORDER_C} strokeWidth={1} />
              <text x={PAD.left - 6} y={y + 4} textAnchor="end" fontSize={10} fill={TEXT3}>
                ${(v / 1000).toFixed(0)}k
              </text>
            </g>
          );
        })}

        {/* Area fill */}
        <polygon points={areaPoints} fill={BLUE_BTN} fillOpacity={0.08} />

        {/* Line */}
        <polyline points={points} fill="none" stroke={BLUE} strokeWidth={2} strokeLinejoin="round" />

        {/* Dots at endpoints */}
        <circle cx={toX(0)} cy={toY(values[0])} r={3} fill={BLUE} />
        <circle cx={toX(snapshots.length - 1)} cy={toY(values[values.length - 1])} r={4} fill={BLUE} />

        {/* X-axis labels */}
        {labelIdxs.map(i => (
          <text key={i} x={toX(i)} y={H - 4} textAnchor="middle" fontSize={10} fill={TEXT3}>
            {new Date(snapshots[i].date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
          </text>
        ))}
      </svg>
    </div>
  );
}

function buildDemoBaseline() {
  const AVG_INCOME = 1270, AVG_SPENDING = 1350;
  const SM = { Q1: 0.92, Q2: 1.00, Q3: 1.03, Q4: 1.18 };
  const BAND = 110;
  const getQ = m => m <= 3 ? 'Q1' : m <= 6 ? 'Q2' : m <= 9 ? 'Q3' : 'Q4';

  // Pre-set net values for the last 12 months: realistic deficit persona with 2 red months
  const NET_VALUES = [-40, -90, -110, -280, -140, -310, -450, -380, 40, 20, -10, -60];

  const now = new Date();
  const months = NET_VALUES.map((net, i) => {
    const d = new Date(now.getFullYear(), now.getMonth() - 11 + i, 1);
    const mo = d.getMonth() + 1;
    const q = getQ(mo);
    const bl = AVG_INCOME - AVG_SPENDING * SM[q];
    return {
      label: `${d.getFullYear()}-${String(mo).padStart(2, '0')}`,
      income: AVG_INCOME + (i % 3 === 2 ? 40 : 0),
      spending: AVG_INCOME + (i % 3 === 2 ? 40 : 0) - net,
      net,
      baseline: bl,
      bandUpper: bl + BAND,
      bandLower: bl - BAND,
      belowBaseline: net < bl - BAND,
    };
  });

  const lastNet = NET_VALUES[NET_VALUES.length - 1];
  const nowMo = now.getMonth() + 1;
  const q = getQ(nowMo);
  const bl = AVG_INCOME - AVG_SPENDING * SM[q];
  const mtdFrac = now.getDate() / new Date(now.getFullYear(), nowMo, 0).getDate();
  const projectedNet = lastNet / Math.max(mtdFrac, 0.01);
  const status = projectedNet < bl - BAND ? 'red' : projectedNet < bl ? 'warning' : 'good';

  return {
    baseline: { avgMonthlyIncome: AVG_INCOME, avgMonthlySpending: AVG_SPENDING, avgMonthlyNet: -80, monthsOfData: 12 },
    months,
    currentMTD: { net: Math.round(lastNet * mtdFrac), projectedNet: Math.round(projectedNet), baseline: bl, pctOfMonth: Math.round(mtdFrac * 100) },
    status,
    isDemo: true,
  };
}
const DEMO_BASELINE = buildDemoBaseline();

function buildDemoSnapshots() {
  // Align with demo data: (checking $3,240 + savings $5,800 + credit card $748) + portfolio $7,832 − liabilities ($124 + $2,800) ≈ $14,696
  const CURRENT_NW = 14696;
  const START_NW   = 12800;
  const DAYS = 30;
  const now = new Date();
  const snapshots = [];
  for (let i = DAYS - 1; i >= 0; i--) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    const t = (DAYS - 1 - i) / (DAYS - 1);
    const base = START_NW + t * (CURRENT_NW - START_NW);
    const daySeed = d.getDate() * 17 + (d.getMonth() + 1) * 31;
    const noise = Math.sin(daySeed * 0.7) * 220 + Math.cos(daySeed * 1.3) * 140;
    snapshots.push({ date: d.toISOString().split('T')[0], value: Math.round(base + noise) });
  }
  return snapshots;
}
const DEMO_SNAPSHOTS = buildDemoSnapshots();

function BaselineChart({ months, baseline, currentMTD, status, onRefresh, refreshing, isDemo }) {
  const W = 620, H = 180, PAD = { top: 20, right: 16, bottom: 32, left: 68 };
  const innerW = W - PAD.left - PAD.right;
  const innerH = H - PAD.top - PAD.bottom;

  const allVals = months.flatMap(m => [m.net, m.bandUpper, m.bandLower]);
  const minV = Math.min(...allVals);
  const maxV = Math.max(...allVals);
  const range = maxV - minV || 1;
  const pad = range * 0.12;
  const lo = minV - pad, hi = maxV + pad, span = hi - lo;

  const toX = i => PAD.left + (i / Math.max(months.length - 1, 1)) * innerW;
  const toY = v => PAD.top + innerH - ((v - lo) / span) * innerH;
  const zeroY = toY(0);

  const netPts = months.map((m, i) => `${toX(i)},${toY(m.net)}`).join(' ');
  const bandTopPts = months.map((m, i) => `${toX(i)},${toY(m.bandUpper)}`).join(' ');
  const bandBotPts = [...months].reverse().map((m, i) => `${toX(months.length - 1 - i)},${toY(m.bandLower)}`).join(' ');

  const statusColor = status === 'red' ? '#f87171' : status === 'warning' ? '#fbbf24' : '#4ade80';
  const statusLabel = status === 'red' ? 'Below Baseline' : status === 'warning' ? 'Trending Low' : 'On Track';

  const MONTH_SHORT = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const labelStep = months.length <= 6 ? 1 : months.length <= 9 ? 2 : 3;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
        <div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <div style={{ width: 8, height: 8, borderRadius: '50%', background: statusColor }} />
            <span style={{ fontSize: 12, color: statusColor, fontWeight: 600 }}>{statusLabel}</span>
          </div>
          {currentMTD && (
            <span style={{ fontSize: 12, color: '#8e8e93' }}>
              {currentMTD.pctOfMonth}% through month · projecting{' '}
              <span style={{ color: currentMTD.projectedNet >= currentMTD.baseline ? '#4ade80' : '#f87171', fontWeight: 600, fontFamily: 'monospace' }}>
                {currentMTD.projectedNet >= 0 ? '+' : ''}{new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(currentMTD.projectedNet)}
              </span>
            </span>
          )}
        </div>
        {!isDemo && (
          <button onClick={onRefresh} disabled={refreshing}
            style={{ background: 'none', border: 'none', color: '#444', fontSize: 11, cursor: refreshing ? 'default' : 'pointer', opacity: refreshing ? 0.5 : 1 }}>
            {refreshing ? 'Updating…' : '↻ Refresh'}
          </button>
        )}
      </div>

      <svg viewBox={`0 0 ${W} ${H}`} style={{ width: '100%', height: 'auto', display: 'block' }}>
        {/* Zero line */}
        {zeroY > PAD.top && zeroY < PAD.top + innerH && (
          <line x1={PAD.left} x2={W - PAD.right} y1={zeroY} y2={zeroY} stroke="#333" strokeWidth={1} strokeDasharray="3,3" />
        )}

        {/* Grid lines */}
        {[0.25, 0.5, 0.75].map(t => {
          const y = PAD.top + t * innerH;
          return <line key={t} x1={PAD.left} x2={W - PAD.right} y1={y} y2={y} stroke="#222" strokeWidth={1} />;
        })}

        {/* Baseline band */}
        <polygon points={`${bandTopPts} ${bandBotPts}`} fill="#4da3ff" fillOpacity={0.08} />
        {/* Band border lines */}
        <polyline points={bandTopPts} fill="none" stroke="#4da3ff" strokeWidth={1} strokeDasharray="4,3" strokeOpacity={0.4} />
        <polyline points={months.map((m, i) => `${toX(i)},${toY(m.bandLower)}`).join(' ')} fill="none" stroke="#4da3ff" strokeWidth={1} strokeDasharray="4,3" strokeOpacity={0.4} />

        {/* Actual net line — red segments when below baseline */}
        {months.map((m, i) => {
          if (i === 0) return null;
          const prev = months[i - 1];
          const color = m.belowBaseline || prev.belowBaseline ? '#f87171' : '#4ade80';
          return (
            <line key={i}
              x1={toX(i - 1)} y1={toY(prev.net)}
              x2={toX(i)} y2={toY(m.net)}
              stroke={color} strokeWidth={2.5} strokeLinejoin="round" strokeLinecap="round"
            />
          );
        })}

        {/* Data point dots */}
        {months.map((m, i) => (
          <circle key={i} cx={toX(i)} cy={toY(m.net)} r={3}
            fill={m.belowBaseline ? '#f87171' : '#4ade80'}
            stroke="#0f0f0f" strokeWidth={1.5}
          />
        ))}

        {/* Y-axis labels */}
        {[0, 0.33, 0.67, 1].map(t => {
          const v = lo + t * span;
          const y = PAD.top + (1 - t) * innerH;
          return (
            <text key={t} x={PAD.left - 6} y={y + 4} textAnchor="end" fontSize={9} fill="#555">
              {v >= 0 ? '+' : ''}{(v / 1000).toFixed(0)}k
            </text>
          );
        })}

        {/* X-axis labels */}
        {months.map((m, i) => {
          if (i % labelStep !== 0 && i !== months.length - 1) return null;
          const [, mo] = m.label.split('-');
          return (
            <text key={i} x={toX(i)} y={H - 4} textAnchor="middle" fontSize={9} fill="#555">
              {MONTH_SHORT[parseInt(mo) - 1]}
            </text>
          );
        })}
      </svg>

      <div style={{ display: 'flex', gap: 20, marginTop: 10 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
          <div style={{ width: 20, height: 2, background: '#4da3ff', opacity: 0.5, borderTop: '1px dashed #4da3ff' }} />
          <span style={{ fontSize: 10, color: '#555' }}>Your baseline range</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
          <div style={{ width: 12, height: 12, borderRadius: '50%', background: '#4ade80' }} />
          <span style={{ fontSize: 10, color: '#555' }}>Above baseline</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
          <div style={{ width: 12, height: 12, borderRadius: '50%', background: '#f87171' }} />
          <span style={{ fontSize: 10, color: '#555' }}>Below baseline</span>
        </div>
      </div>
    </div>
  );
}

function TickerBar({ indices, active }) {
  const all = [...indices, ...active];
  if (!all.length) return null;

  const item = (t, key) => (
    <span key={key} style={{ display: 'inline-flex', alignItems: 'center', gap: 8, marginRight: 32, whiteSpace: 'nowrap' }}>
      <span style={{ fontSize: 12, color: TEXT2, fontWeight: 700 }}>{t.name}</span>
      <span style={{ fontFamily: 'monospace', fontSize: 13, color: TEXT }}>
        {(t.price || 0).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
      </span>
      <span style={{ fontSize: 11, fontWeight: 600, color: (t.changePct || 0) >= 0 ? GREEN : RED }}>
        {(t.changePct || 0) >= 0 ? '▲' : '▼'} {Math.abs(t.changePct || 0).toFixed(2)}%
      </span>
      <span style={{ color: BORDER_C, fontSize: 11 }}>│</span>
    </span>
  );

  return (
    <div style={{ height: 42, background: SIDE_BG, borderBottom: BORDER, display: 'flex', alignItems: 'center', overflow: 'hidden', flexShrink: 0 }}>
      <div className="ticker-scroll">
        {all.map((t, i) => item(t, i))}
        {all.map((t, i) => item(t, i + all.length))}
      </div>
    </div>
  );
}

function SP500Chart({ candles, period, onPeriodChange, hidePeriods }) {
  if (!candles || candles.length < 2) {
    return (
      <div style={{ height: 180, display: 'flex', alignItems: 'center', justifyContent: 'center', color: TEXT2, fontSize: 13 }}>
        {!candles || candles.length === 0 ? 'Chart unavailable' : 'Loading chart…'}
      </div>
    );
  }

  const W = 600, H = 180, PAD = { top: 20, right: 16, bottom: 30, left: 72 };
  const innerW = W - PAD.left - PAD.right;
  const innerH = H - PAD.top - PAD.bottom;

  const values = candles.map(c => c.close);
  const minV = Math.min(...values);
  const maxV = Math.max(...values);
  const range = maxV - minV || 1;

  const toX = i => PAD.left + (i / (candles.length - 1)) * innerW;
  const toY = v => PAD.top + innerH - ((v - minV) / range) * innerH;

  const points = candles.map((c, i) => `${toX(i).toFixed(1)},${toY(c.close).toFixed(1)}`).join(' ');
  const areaPoints = `${PAD.left},${PAD.top + innerH} ${points} ${toX(candles.length - 1).toFixed(1)},${PAD.top + innerH}`;

  const first = values[0];
  const last  = values[values.length - 1];
  const change = last - first;
  const changePct = (change / first) * 100;
  const lineColor = change >= 0 ? GREEN : RED;
  const fillId = change >= 0 ? 'sp500g' : 'sp500r';

  const labelIdxs = Array.from({ length: Math.min(candles.length, 6) }, (_, i) =>
    Math.round((i / (Math.min(candles.length, 6) - 1)) * (candles.length - 1))
  );

  const PERIODS = [
    { key: '1mo', label: '1M' }, { key: '3mo', label: '3M' },
    { key: '6mo', label: '6M' }, { key: '1y',  label: '1Y' },
  ];

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>
        <div style={{ display: 'flex', gap: 14, alignItems: 'baseline' }}>
          <span style={{ fontFamily: 'monospace', fontSize: 22, fontWeight: 700 }}>
            {last.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
          </span>
          <span style={{ fontSize: 13, fontWeight: 600, color: lineColor }}>
            {change >= 0 ? '+' : ''}{change.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
            {' '}({changePct >= 0 ? '+' : ''}{changePct.toFixed(2)}%)
          </span>
        </div>
        {!hidePeriods && (
          <div style={{ display: 'flex', gap: 4 }}>
            {PERIODS.map(({ key, label }) => (
              <button key={key} onClick={() => onPeriodChange(key)} style={{
                padding: '4px 12px', borderRadius: 6, border: 'none', fontSize: 12,
                cursor: 'pointer', fontWeight: 600, transition: 'background 0.15s',
                background: period === key ? BLUE_BTN : MUTED,
                color: period === key ? '#fff' : TEXT2,
              }}>{label}</button>
            ))}
          </div>
        )}
      </div>

      <svg viewBox={`0 0 ${W} ${H}`} style={{ width: '100%', height: 'auto', display: 'block' }}>
        <defs>
          <linearGradient id={fillId} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={lineColor} stopOpacity={0.18} />
            <stop offset="100%" stopColor={lineColor} stopOpacity={0} />
          </linearGradient>
        </defs>
        {[0, 0.5, 1].map(t => {
          const v = minV + t * range;
          const y = toY(v);
          return (
            <g key={t}>
              <line x1={PAD.left} x2={W - PAD.right} y1={y} y2={y} stroke={BORDER_C} strokeWidth={1} strokeDasharray="4 4" />
              <text x={PAD.left - 6} y={y + 4} textAnchor="end" fontSize={10} fill={TEXT3}>
                {v >= 1000 ? (v / 1000).toFixed(1) + 'k' : v.toFixed(0)}
              </text>
            </g>
          );
        })}
        <polygon points={areaPoints} fill={`url(#${fillId})`} />
        <polyline points={points} fill="none" stroke={lineColor} strokeWidth={1.8} strokeLinejoin="round" />
        <circle cx={toX(candles.length - 1)} cy={toY(last)} r={3.5} fill={lineColor} />
        {labelIdxs.map(i => (
          <text key={i} x={toX(i)} y={H - 4} textAnchor="middle" fontSize={10} fill={TEXT3}>
            {new Date(candles[i].date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
          </text>
        ))}
      </svg>
    </div>
  );
}

function FearGreedGauge({ score, rating }) {
  if (score == null) return null;

  const ZONES = [
    { label: 'Extreme Fear',  max: 25,  color: '#ef4444' },
    { label: 'Fear',          max: 45,  color: '#f97316' },
    { label: 'Neutral',       max: 55,  color: '#eab308' },
    { label: 'Greed',         max: 75,  color: '#22c55e' },
    { label: 'Extreme Greed', max: 100, color: '#16a34a' },
  ];
  const zone = ZONES.find(z => score <= z.max) || ZONES[ZONES.length - 1];

  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'flex-end', gap: 12, marginBottom: 18 }}>
        <span style={{ fontSize: 56, fontWeight: 800, fontFamily: 'monospace', color: zone.color, lineHeight: 1 }}>{score}</span>
        <div style={{ paddingBottom: 4 }}>
          <div style={{ fontSize: 16, fontWeight: 700, color: zone.color }}>{zone.label}</div>
          <div style={{ fontSize: 11, color: TEXT3 }}>out of 100</div>
        </div>
      </div>

      <div style={{ position: 'relative', marginBottom: 8 }}>
        <div style={{ height: 10, borderRadius: 5, background: 'linear-gradient(to right, #ef4444 0%, #f97316 25%, #eab308 45%, #22c55e 70%, #16a34a 100%)' }}>
          <div style={{
            position: 'absolute', top: '50%', left: `${score}%`,
            transform: 'translate(-50%, -50%)',
            width: 18, height: 18, borderRadius: '50%',
            background: '#fff', border: `3px solid ${zone.color}`,
            boxShadow: `0 0 0 3px ${zone.color}33, 0 2px 6px rgba(0,0,0,0.5)`,
            transition: 'left 0.4s ease',
          }} />
        </div>
      </div>

      <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: TEXT3, marginTop: 6 }}>
        <span>Extreme Fear</span>
        <span style={{ transform: 'translateX(50%)' }}>Neutral</span>
        <span>Extreme Greed</span>
      </div>

      <div style={{ display: 'flex', gap: 4, marginTop: 14, flexWrap: 'wrap' }}>
        {ZONES.map(z => {
          const active = z.label === zone.label;
          return (
            <div key={z.label} style={{ flex: 1, minWidth: 60, padding: '5px 8px', borderRadius: 6, textAlign: 'center', background: active ? `${z.color}22` : DARK, border: `1px solid ${active ? z.color : BORDER_C}` }}>
              <div style={{ fontSize: 8, fontWeight: 700, whiteSpace: 'nowrap', color: active ? z.color : TEXT3 }}>{z.label}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

